export function downloadRoutingApiContext() {
  const blob = new Blob([ROUTING_API_CLAUDE_CONTEXT], { type: 'text/markdown;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'tomtom-routing-api.md';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}
